import{_ as t,o as a,c as i,ag as h}from"./chunks/framework.nZ6LtKJQ.js";const m=JSON.parse('{"title":"Quản lý tài khoản","description":"","frontmatter":{},"headers":[],"relativePath":"account-management.md","filePath":"account-management.md","lastUpdated":null}'),l={name:"account-management.md"};function o(r,n,e,u,c,s){return a(),i("div",null,[...n[0]||(n[0]=[h('<h1 id="quan-ly-tai-khoan" tabindex="-1">Quản lý tài khoản <a class="header-anchor" href="#quan-ly-tai-khoan" aria-label="Permalink to &quot;Quản lý tài khoản&quot;">​</a></h1><h2 id="xem-va-chinh-sua-thong-tin-ca-nhan" tabindex="-1">Xem và chỉnh sửa thông tin cá nhân <a class="header-anchor" href="#xem-va-chinh-sua-thong-tin-ca-nhan" aria-label="Permalink to &quot;Xem và chỉnh sửa thông tin cá nhân&quot;">​</a></h2><ol><li>Nhấn vào <strong>tên/ảnh đại diện</strong> góc trên phải → chọn <strong>Tài khoản</strong></li><li>Hoặc truy cập thẳng: <code>/profile</code></li></ol><p>Thông tin có thể chỉnh sửa:</p><ul><li><strong>Họ và tên</strong></li><li><strong>Ảnh đại diện</strong> — nhấn vào avatar để tải ảnh mới (JPG/PNG, tối đa 2MB)</li><li><strong>Giới tính</strong></li><li><strong>Ngày sinh</strong></li></ul><p>Nhấn <strong>Lưu thay đổi</strong> sau khi chỉnh sửa xong.</p><hr><h2 id="đoi-mat-khau" tabindex="-1">Đổi mật khẩu <a class="header-anchor" href="#đoi-mat-khau" aria-label="Permalink to &quot;Đổi mật khẩu&quot;">​</a></h2><h3 id="khi-đang-đang-nhap" tabindex="-1">Khi đang đăng nhập <a class="header-anchor" href="#khi-đang-đang-nhap" aria-label="Permalink to &quot;Khi đang đăng nhập&quot;">​</a></h3><ol><li>Vào <strong>Tài khoản → tab Bảo mật</strong></li><li>Điền: <ul><li>Mật khẩu hiện tại</li><li>Mật khẩu mới (tối thiểu 8 ký tự)</li><li>Xác nhận mật khẩu mới</li></ul></li><li>Nhấn <strong>Cập nhật mật khẩu</strong></li></ol><h3 id="quen-mat-khau" tabindex="-1">Quên mật khẩu <a class="header-anchor" href="#quen-mat-khau" aria-label="Permalink to &quot;Quên mật khẩu&quot;">​</a></h3><ol><li>Trang đăng nhập → nhấn <strong>Quên mật khẩu?</strong></li><li>Nhập địa chỉ email đã đăng ký → nhấn <strong>Gửi link đặt lại</strong></li><li>Kiểm tra email (kể cả thư mục Spam) → nhấn link trong email</li><li>Đặt mật khẩu mới → nhấn <strong>Xác nhận</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Link đặt lại mật khẩu chỉ có hiệu lực trong <strong>1 giờ</strong>. Nếu hết hạn, thực hiện lại từ bước 1.</p></div><hr><h2 id="luu-y-bao-mat" tabindex="-1">Lưu ý bảo mật <a class="header-anchor" href="#luu-y-bao-mat" aria-label="Permalink to &quot;Lưu ý bảo mật&quot;">​</a></h2><ul><li>Không chia sẻ mật khẩu với bất kỳ ai, kể cả giáo viên hay admin</li><li>Sử dụng mật khẩu riêng biệt, không dùng lại mật khẩu từ các nền tảng khác</li><li>Nếu nghi ngờ tài khoản bị xâm phạm, đổi mật khẩu ngay và liên hệ admin</li></ul>',16)])])}const k=t(l,[["render",o]]);export{m as __pageData,k as default};
